import{_ as o,o as l,c as i,ai as a}from"./chunks/framework.ampVZV4B.js";const m=JSON.parse('{"title":"电话 / 视频沟通模板","description":"","frontmatter":{},"headers":[],"relativePath":"english-speaking/templates-call.md","filePath":"english-speaking/templates-call.md"}'),c={name:"english-speaking/templates-call.md"};function t(d,e,r,s,n,h){return l(),i("div",null,[...e[0]||(e[0]=[a('<h1 id="电话-视频沟通模板" tabindex="-1">电话 / 视频沟通模板 <a class="header-anchor" href="#电话-视频沟通模板" aria-label="Permalink to “电话 / 视频沟通模板”">​</a></h1><blockquote><p>这一篇适合打电话、语音、视频会议时使用。<br> 这类场景最常见的问题是：<strong>听不清、卡顿、确认信息、礼貌衔接</strong>。</p></blockquote><hr><h2 id="_1-接通与确认-10-句" tabindex="-1">1. 接通与确认（10 句） <a class="header-anchor" href="#_1-接通与确认-10-句" aria-label="Permalink to “1. 接通与确认（10 句）”">​</a></h2><ol><li><code>Hello, this is [your name].</code></li><li><code>Hi, am I speaking to [name]?</code></li><li><code>Can you hear me clearly?</code></li><li><code>Can you see my screen?</code></li><li><code>Is the audio okay on your side?</code></li><li><code>Thanks for joining the call.</code></li><li><code>Let&#39;s wait a minute for the others to join.</code></li><li><code>Can we start now?</code></li><li><code>I&#39;m calling about today&#39;s update.</code></li><li><code>I&#39;m reaching out to discuss this issue.</code></li></ol><h2 id="_2-听不清-网络问题-10-句" tabindex="-1">2. 听不清 / 网络问题（10 句） <a class="header-anchor" href="#_2-听不清-网络问题-10-句" aria-label="Permalink to “2. 听不清 / 网络问题（10 句）”">​</a></h2><ol start="11"><li><code>Your voice is breaking up.</code></li><li><code>The connection is a bit unstable.</code></li><li><code>I can&#39;t hear you very well.</code></li><li><code>Could you say that again?</code></li><li><code>Could you speak a little louder?</code></li><li><code>I think your microphone is muted.</code></li><li><code>The screen is frozen on my side.</code></li><li><code>You cut out for a second.</code></li><li><code>Let me reconnect quickly.</code></li><li><code>Could you type it in the chat?</code></li></ol><h2 id="_3-转入正题-10-句" tabindex="-1">3. 转入正题（10 句） <a class="header-anchor" href="#_3-转入正题-10-句" aria-label="Permalink to “3. 转入正题（10 句）”">​</a></h2><ol start="21"><li><code>Let&#39;s get to the main point.</code></li><li><code>I&#39;m calling to follow up on this matter.</code></li><li><code>I want to quickly go over the current status.</code></li><li><code>There are two things I&#39;d like to discuss.</code></li><li><code>The main reason for this call is this.</code></li><li><code>Let&#39;s review the issue step by step.</code></li><li><code>I&#39;ll keep it brief.</code></li><li><code>Here&#39;s what we need to decide today.</code></li><li><code>Let&#39;s focus on the key issue first.</code></li><li><code>I want to make sure we&#39;re aligned before moving on.</code></li></ol><h2 id="_4-电话中确认信息-10-句" tabindex="-1">4. 电话中确认信息（10 句） <a class="header-anchor" href="#_4-电话中确认信息-10-句" aria-label="Permalink to “4. 电话中确认信息（10 句）”">​</a></h2><ol start="31"><li><code>Let me repeat that to make sure I got it right.</code></li><li><code>So you&#39;re saying that...?</code></li><li><code>Just to confirm, the deadline is Friday, right?</code></li><li><code>Can you send me the details later?</code></li><li><code>I&#39;ll write that down.</code></li><li><code>Let me check if I understood correctly.</code></li><li><code>Could you confirm the final version?</code></li><li><code>Who will handle this part?</code></li><li><code>What should I do next?</code></li><li><code>I&#39;ll follow up after the call.</code></li></ol><h2 id="_5-留言-回拨-收尾-10-句" tabindex="-1">5. 留言 / 回拨 / 收尾（10 句） <a class="header-anchor" href="#_5-留言-回拨-收尾-10-句" aria-label="Permalink to “5. 留言 / 回拨 / 收尾（10 句）”">​</a></h2><ol start="41"><li><code>He&#39;s not available right now.</code></li><li><code>Can I take a message?</code></li><li><code>Could you ask him to call me back?</code></li><li><code>I&#39;ll call you back later.</code></li><li><code>Let&#39;s continue this later.</code></li><li><code>I&#39;ll send a summary after this call.</code></li><li><code>Thanks for your time.</code></li><li><code>Talk to you again soon.</code></li><li><code>Have a great day.</code></li><li><code>Goodbye for now.</code></li></ol><hr><h2 id="使用建议" tabindex="-1">使用建议 <a class="header-anchor" href="#使用建议" aria-label="Permalink to “使用建议”">​</a></h2><ul><li>电话 / 视频里最关键的是 <code>3-5</code>、<code>11-20</code>、<code>31-40</code></li><li>如果紧张，就反复练“确认型句子”</li><li>真实通话时，宁可慢一点，也不要一口气说太长</li></ul>',16)])])}const y=o(c,[["render",t]]);export{m as __pageData,y as default};
